{
  "description": "Derive the set of project filesystem paths from a path-configuration document, relative to the application root. The configuration supplies logical names for the JavaScript source directory, the entry subdirectory, the compiled-output subdirectory (under the application's public directory), the manifest filename, and the build-config directory. The system resolves: the raw source name; the absolute source directory; the entry directory (source directory joined with the entry name); the output directory (public directory joined with the output name); the manifest path (output directory joined with the manifest filename); the build-config directory; and the fixed location of the path-configuration document itself (always config/webpack/paths.yml under the root). Any key missing from the supplied configuration falls back to a built-in default.",
  "cases": [
    {
      "input": {
        "action": "config_paths",
        "root": "/app"
      },
      "expected_output": "source=app/javascript\nsource_path=/app/app/javascript\nentry_path=/app/app/javascript/packs\noutput_path=/app/public/packs\nmanifest_path=/app/public/packs/manifest.json\nconfig_path=/app/config/webpack\nfile_path=/app/config/webpack/paths.yml\n"
    },
    {
      "input": {
        "action": "config_paths",
        "root": "/srv/app",
        "paths": {
          "production": {
            "source": "frontend",
            "entry": "entries",
            "output": "assets",
            "manifest": "manifest.json",
            "config": "config/webpack"
          }
        }
      },
      "expected_output": "source=frontend\nsource_path=/srv/app/frontend\nentry_path=/srv/app/frontend/entries\noutput_path=/srv/app/public/assets\nmanifest_path=/srv/app/public/assets/manifest.json\nconfig_path=/srv/app/config/webpack\nfile_path=/srv/app/config/webpack/paths.yml\n"
    }
  ]
}
